  ('diplomatic-d3cf880d-moex-00436', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '依維也納條約法公約，關於「條約的解釋」，下列敘述何者正確？', '["條約用語總是採用特殊的意義", "依照上下文解釋條約時，無須考慮條約的弁言", "條約用語應依條約目的與宗旨而善意解釋之", "依照上下文脈絡解釋條約時，無須考慮條約的附件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
