  ('diplomatic-d3cf880d-moex-00438', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '國際法院在 2010 年公布有關科索沃獨立宣言合法性的諮詢意見。關於這份諮詢意見，下列敘述 何者正確？', '["此諮詢意見係由塞爾維亞向國際法院提出請求而作成", "國際法院認為科索沃宣布獨立之行為未違反國際法", "國際法院認為人民自決權於殖民地人民範疇外亦適用", "國際法院認為其他國家承認科索沃為獨立國家有溯及至宣布獨立之日的效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00439', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '被請求國經由引渡程序，將人犯解交請求國時，請求國僅能就引渡請求書中所載之犯罪為追訴或 處罰，此原則稱為：', '["互惠原則", "再引渡原則", "特定行為原則", "雙重犯罪原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00440', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '沿海國在專屬經濟海域有何種權利？', '["沿海國對專屬經濟區擁有主權", "自然資源探勘、開發、養護和管理，但僅限於生物資源", "自然資源探勘、開發、養護和管理，但僅限於非生物資源", "利用風力生產能源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00441', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '依維也納外交關係公約，若外交代表為接受國國民，下列敘述何者正確？', '["外交代表無以證人身分作證之義務", "外交代表對接受國之刑事管轄均享有豁免", "外交代表原則上僅就其執行職務之公務行為，享有管轄之豁免及不得侵犯權", "外交代表不受任何方式之逮捕或拘禁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00442', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '1963年訂立的「航空器上所犯罪行及若干其他行為（東京）公約」第4條規定，如果在飛機上的 罪行是對一個締約國國民或其永久居民所為者，該締約國可以行使管轄權。上述規定採取那一種 管轄原則？', '["保護管轄", "被害人（消極）國籍管轄", "國籍（積極）管轄", "領域管轄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00443', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-111-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '關於「國家責任」，下列敘述何者錯誤？', '["依據2001年《國家國際不法行為責任條款草案》第4條規定，任何國家機構所為之行為，皆應 視為國際法上之國家行為，無論該機構之特徵以及其所執行之功能", "國家如對他國利益直接造成損害，應負擔國家責任", "國家可以該國法律或憲法規定而主張對於國際索償之抗辯", "2001年《國家國際不法行為責任條款草案》第11條規定，國家只有在認知並採取有關行為時， 將其視為本國行為的情況下，才有國家責任之產生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:47+00:00", "source_pdf_sha1": "e1a4d6d077aa", "answer_pdf_sha1": "daee9d1e682f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
